// Beispiel: q steckt unter json.body.q
const qRaw = items[0].json.body?.q ?? items[0].json.params?.q ?? "";
const q = qRaw.toLowerCase();

// Deine Mock-Chunks
const all = [
  { id: "c1", text: "Isolierklasse H05VV-F gemäß DIN VDE 0298-4" },
  { id: "c2", text: "Mantelstärke mindestens 0,5 mm²" },
  { id: "c3", text: "Farbkennzeichnung nach Tabelle 11" },
  { id: "c4", text: "Mindestabstand 5 mm zu scharfen Kanten" }
];

// Filter anwenden
const filtered = all.filter(chunk =>
  chunk.text.toLowerCase().includes(q)
);

// Gib nur die gefundenen Chunks zurück
return filtered.map(chunk => ({ json: chunk }));
